package app

import example.SpellCaster
import org.junit.Test
import org.junit.Assert.*

@SpellCaster
class WizardTest {
    @Test
    fun testFavoriteSpell() {
        // Uses Java code generated by kapt for main source
        assertEquals("Expelliarmus from Wizard", WizardSpellBook.favoriteSpell())
    }

    @Test
    fun testKotlinExtension() {
        // Uses Kotlin extension generated by kapt for main source
        val wizard = Wizard()
        assertTrue(wizard.castSpell().contains("Wizard"))
    }

    @Test
    fun testTestKaptGeneration() {
        // Uses Java code generated by test-kapt for this test class
        assertEquals("Expelliarmus from WizardTest", WizardTestSpellBook.favoriteSpell())
    }
}
